{
  "name": "crm-system-prototype",
  "version": "0.1.0",
  "private": true,
  "dependencies": {
    "react": "^18.2.0",
    "react-dom": "^18.2.0",
    "react-scripts": "5.0.1"
  },
  "scripts": {
    "start": "react-scripts start",
    "build": "react-scripts build",
    "test": "react-scripts test",
    "eject": "react-scripts eject"
  },
  "browserslist": {
    "production": [
      ">0.2%",
      "not dead",
      "not op_mini all"
    ],
    "development": [
      "last 1 chrome version",
      "last 1 firefox version",
      "last 1 safari version"
    ]
  }
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';

const customersSample = [
  { id: 1, name: 'عميل 1', email: 'client1@example.com', phone: '0500000001' },
  { id: 2, name: 'عميل 2', email: 'client2@example.com', phone: '0500000002' }
];

const salesSample = [
  { id: 1, customer: 'عميل 1', product: 'منتج أ', amount: 1000, date: '2024-05-01' },
  { id: 2, customer: 'عميل 2', product: 'منتج ب', amount: 2000, date: '2024-05-03' }
];

const marketingSample = [
  { id: 1, campaign: 'حملة رمضان', status: 'نشطة' },
  { id: 2, campaign: 'حملة الصيف', status: 'مكتملة' }
];

const supportSample = [
  { id: 1, ticket: '1234', customer: 'عميل 1', issue: 'مشكلة في المنتج', status: 'مفتوح' },
  { id: 2, ticket: '1235', customer: 'عميل 2', issue: 'طلب دعم', status: 'مغلق' }
];

function App() {
  const [view, setView] = useState('customers');

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', maxWidth: 900, margin: 'auto', padding: 20 }}>
      <h1>نظام إدارة علاقات العملاء (CRM) - نموذج أولي</h1>
      <nav style={{ marginBottom: 20 }}>
        <button onClick={() => setView('customers')} style={{ marginRight: 10 }}>إدارة العملاء</button>
        <button onClick={() => setView('sales')} style={{ marginRight: 10 }}>تتبع المبيعات</button>
        <button onClick={() => setView('marketing')} style={{ marginRight: 10 }}>التسويق</button>
        <button onClick={() => setView('support')}>الدعم الفني</button>
      </nav>

      {view === 'customers' && <CustomersView />}
      {view === 'sales' && <SalesView />}
      {view === 'marketing' && <MarketingView />}
      {view === 'support' && <SupportView />}
    </div>
  );
}

function CustomersView() {
  return (
    <div>
      <h2>إدارة العملاء</h2>
      <table border="1" cellPadding="5" cellSpacing="0" style={{ width: '100%', textAlign: 'right' }}>
        <thead>
          <tr>
            <th>الرقم</th>
            <th>الاسم</th>
            <th>البريد الإلكتروني</th>
            <th>رقم الهاتف</th>
          </tr>
        </thead>
        <tbody>
          {customersSample.map(c => (
            <tr key={c.id}>
              <td>{c.id}</td>
              <td>{c.name}</td>
              <td>{c.email}</td>
              <td>{c.phone}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function SalesView() {
  return (
    <div>
      <h2>تتبع المبيعات</h2>
      <table border="1" cellPadding="5" cellSpacing="0" style={{ width: '100%', textAlign: 'right' }}>
        <thead>
          <tr>
            <th>الرقم</th>
            <th>العميل</th>
            <th>المنتج</th>
            <th>المبلغ</th>
            <th>التاريخ</th>
          </tr>
        </thead>
        <tbody>
          {salesSample.map(s => (
            <tr key={s.id}>
              <td>{s.id}</td>
              <td>{s.customer}</td>
              <td>{s.product}</td>
              <td>{s.amount}</td>
              <td>{s.date}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function MarketingView() {
  return (
    <div>
      <h2>التسويق</h2>
      <table border="1" cellPadding="5" cellSpacing="0" style={{ width: '100%', textAlign: 'right' }}>
        <thead>
          <tr>
            <th>الرقم</th>
            <th>الحملة</th>
            <th>الحالة</th>
          </tr>
        </thead>
        <tbody>
          {marketingSample.map(m => (
            <tr key={m.id}>
              <td>{m.id}</td>
              <td>{m.campaign}</td>
              <td>{m.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function SupportView() {
  return (
    <div>
      <h2>الدعم الفني</h2>
      <table border="1" cellPadding="5" cellSpacing="0" style={{ width: '100%', textAlign: 'right' }}>
        <thead>
          <tr>
            <th>رقم التذكرة</th>
            <th>العميل</th>
            <th>المشكلة</th>
            <th>الحالة</th>
          </tr>
        </thead>
        <tbody>
          {supportSample.map(s => (
            <tr key={s.id}>
              <td>{s.ticket}</td>
              <td>{s.customer}</td>
              <td>{s.issue}</td>
              <td>{s.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;

body {
  margin: 0;
  padding: 0;
  direction: rtl;
  background-color: #f9f9f9;
  color: #333;
}

button {
  cursor: pointer;
  padding: 8px 12px;
  font-size: 14px;
  border: 1px solid #ccc;
  background-color: #fff;
  border-radius: 4px;
  transition: background-color 0.3s ease;
}

button:hover {
  background-color: #e6e6e6;
}

h1, h2 {
  color: #2c3e50;
}

table {
  background-color: #fff;
  border-collapse: collapse;
}

th {
  background-color: #3498db;
  color: white;
}
